                            (HWREGH(ANALOGSUBSYS_BASE + ASYSCTL_O_ANAREFPCTL) &
                            ~refMask) | reference;

    HWREGH(ANALOGSUBSYS_BASE + ASYSCTL_O_ANAREFNCTL) =
                            (HWREGH(ANALOGSUBSYS_BASE + ASYSCTL_O_ANAREFNCTL) &
                            ~refMask) | reference;

    EDIS;

}

